# CoAP Constants
COAP_VERSION = 1
COAP_PORT = 5683

# CoAP Message Types
CON = 0  # Confirmable
NON = 1  # Non-confirmable
ACK = 2  # Acknowledgement
RST = 3  # Reset

# CoAP Method Codes
EMPTY = 0
GET = 1
POST = 2
PUT = 3
DELETE = 4

# CoAP Response Codes
CREATED = (2, 1)
DELETED = (2, 2)
VALID = (2, 3)
CHANGED = (2, 4)
CONTENT = (2, 5)
BAD_REQUEST = (4, 0)
NOT_FOUND = (4, 4)
METHOD_NOT_ALLOWED = (4, 5)
INTERNAL_ERROR = (5, 0)

# Content Format
TEXT_PLAIN = 0
APP_JSON = 50


class CoapOption:
    def __init__(self, number, value=b''):
        self.number = number
        self.value = value


class CoapMessage:
    def __init__(self):
        self.version = COAP_VERSION
        self.type = CON
        self.token_length = 0
        self.code_class = 0
        self.code_detail = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''

    @property
    def uri_path(self):
        parts = []
        for opt in self.options:
            if opt.number == 11:  # Uri-Path
                parts.append(opt.value.decode('utf-8'))
        return '/' + '/'.join(parts) if parts else '/'

    def encode(self):
        buf = bytearray()
        # Header
        header = (self.version << 6) | (self.type << 4) | (self.token_length & 0x0F)
        buf.append(header)
        code = ((self.code_class & 0x07) << 5) | (self.code_detail & 0x1F)
        buf.append(code)
        buf.append((self.message_id >> 8) & 0xFF)
        buf.append(self.message_id & 0xFF)

        # Token
        if self.token:
            buf.extend(self.token)

        # Options (sorted by number)
        self.options.sort(key=lambda o: o.number)
        prev_number = 0
        for opt in self.options:
            delta = opt.number - prev_number
            length = len(opt.value)

            # Encode delta
            if delta < 13:
                d = delta
                d_ext = b''
            elif delta < 269:
                d = 13
                d_ext = bytes([delta - 13])
            else:
                d = 14
                d_ext = struct.pack('!H', delta - 269)

            # Encode length
            if length < 13:
                l = length
                l_ext = b''
            elif length < 269:
                l = 13
                l_ext = bytes([length - 13])
            else:
                l = 14
                l_ext = struct.pack('!H', length - 269)

            buf.append((d << 4) | l)
            buf.extend(d_ext)
            buf.extend(l_ext)
            buf.extend(opt.value)
            prev_number = opt.number

        # Payload marker + payload
        if self.payload:
            buf.append(0xFF)
            buf.extend(self.payload)

        return bytes(buf)

    @staticmethod
    def decode(data):
        msg = CoapMessage()
        if len(data) < 4:
            return None

        header = data[0]
        msg.version = (header >> 6) & 0x03
        msg.type = (header >> 4) & 0x03
        msg.token_length = header & 0x0F

        code = data[1]
        msg.code_class = (code >> 5) & 0x07
        msg.code_detail = code & 0x1F

        msg.message_id = (data[2] << 8) | data[3]

        idx = 4

        # Token
        if msg.token_length > 0:
            msg.token = data[idx:idx + msg.token_length]
            idx += msg.token_length

        # Options
        prev_number = 0
        while idx < len(data):
            if data[idx] == 0xFF:
                idx += 1
                break

            byte = data[idx]
            idx += 1
            delta = (byte >> 4) & 0x0F
            length = byte & 0x0F

            if delta == 13:
                delta = data[idx] + 13
                idx += 1
            elif delta == 14:
                delta = struct.unpack('!H', data[idx:idx + 2])[0] + 269
                idx += 2

            if length == 13:
                length = data[idx] + 13
                idx += 1
            elif length == 14:
                length = struct.unpack('!H', data[idx:idx + 2])[0] + 269
                idx += 2

            opt_number = prev_number + delta
            opt_value = data[idx:idx + length]
            idx += length

            msg.options.append(CoapOption(opt_number, opt_value))
            prev_number = opt_number

        # Payload
        if idx < len(data):
            msg.payload = data[idx:]

        return msg


class DeviceState:
    """Holds the current state of all device resources."""

    def __init__(self):
        self.light_state = False
        self.light_brightness = 0
        self._adc = None
        self._init_hardware()

    def _init_hardware(self):
        try:
            # Initialize ADC for temperature sensor (e.g., on GPIO 36 / ADC0)
            self._adc = machine.ADC(machine.Pin(36))
            self._adc.atten(machine.ADC.ATTN_11DB)
            self._adc.width(machine.ADC.WIDTH_12BIT)
        except Exception:
            self._adc = None

        try:
            # Initialize LED/light actuator pin
            self._light_pin = machine.Pin(2, machine.Pin.OUT)
        except Exception:
            self._light_pin = None

    def read_temperature(self):
        """Read temperature from ADC sensor. Returns dict with temp data."""
        if self._adc:
            raw = self._adc.read()
            # Convert raw ADC to voltage then to temperature (LM35-like)
            voltage = raw * 3.3 / 4095.0
            temp_c = voltage * 100.0
        else:
            # Simulated temperature for testing
            import urandom
            temp_c = 20.0 + (urandom.getrandbits(8) % 150) / 10.0

        return {
            "temperature": round(temp_c, 2),
            "unit": "celsius",
            "timestamp": time.time()
        }

    def get_light_state(self):
        """Return current light/actuator state."""
        return {
            "on": self.light_state,
            "brightness": self.light_brightness,
            "timestamp": time.time()
        }

    def set_light_state(self, payload):
        """Set light state from payload. Returns True on success."""
        try:
            if isinstance(payload, (bytes, bytearray)):
                payload = payload.decode('utf-8')
            data = json.loads(payload)
        except (ValueError, UnicodeError):
            # Try simple text: "on", "off", or brightness number
            payload_str = payload.strip().lower() if isinstance(payload, str) else payload.decode().strip().lower()
            if payload_str in ('on', '1', 'true'):
                data = {"on": True}
            elif payload_str in ('off', '0', 'false'):
                data = {"on": False}
            else:
                try:
                    brightness = int(payload_str)
                    data = {"brightness": brightness, "on": brightness > 0}
                except ValueError:
                    return False

        if "on" in data:
            self.light_state = bool(data["on"])
        if "brightness" in data:
            self.light_brightness = max(0, min(100, int(data["brightness"])))
            self.light_state = self.light_brightness > 0

        # Apply to hardware
        if self._light_pin:
            self._light_pin.value(1 if self.light_state else 0)

        print("[ACTUATOR] Light: on={}, brightness={}".format(
            self.light_state, self.light_brightness))
        return True


class CoapResource:
    """Represents a single CoAP resource with handlers."""

    def __init__(self, path, get_handler=None, put_handler=None,
                 content_format=APP_JSON):
        self.path = path
        self.get_handler = get_handler
        self.put_handler = put_handler
        self.content_format = content_format


class CoapServer:
    """Lightweight CoAP server for MicroPython IoT devices."""

    def __init__(self, host='0.0.0.0', port=COAP_PORT):
        self.host = host
        self.port = port
        self.resources = {}
        self._sock = None
        self._running = False
        self._msg_id_counter = 0

    def add_resource(self, resource):
        """Register a CoAP resource."""
        self.resources[resource.path] = resource
        print("[CoAP] Resource registered: {}".format(resource.path))

    def _next_msg_id(self):
        self._msg_id_counter = (self._msg_id_counter + 1) & 0xFFFF
        return self._msg_id_counter

    def _build_response(self, request, code, payload=b'', content_format=None):
        """Build a CoAP response message."""
        resp = CoapMessage()
        resp.version = COAP_VERSION

        if request.type == CON:
            resp.type = ACK
        else:
            resp.type = NON

        resp.code_class = code[0]
        resp.code_detail = code[1]
        resp.message_id = request.message_id
        resp.token = request.token
        resp.token_length = len(request.token)

        if content_format is not None and payload:
            resp.options.append(CoapOption(12, struct.pack('!B', content_format)))

        if isinstance(payload, str):
            payload = payload.encode('utf-8')
        resp.payload = payload

        return resp

    def _handle_request(self, data, addr):
        """Parse and handle an incoming CoAP request."""
        msg = CoapMessage.decode(data)
        if msg is None:
            print("[CoAP] Failed to decode message from {}".format(addr))
            return None

        uri = msg.uri_path
        method_code = msg.code_detail

        print("[CoAP] {} {} from {}".format(
            {GET: 'GET', PUT: 'PUT', POST: 'POST', DELETE: 'DELETE'}.get(method_code, '?'),
            uri, addr))

        # Well-known core resource discovery
        if uri == '/.well-known/core' and method_code == GET:
            return self._handle_discovery(msg)

        # Find matching resource
        resource = self.resources.get(uri)
        if resource is None:
            return self._build_response(msg, NOT_FOUND,
                                        b'Resource not found')

        if method_code == GET:
            if resource.get_handler:
                try:
                    result = resource.get_handler()
                    if isinstance(result, dict):
                        payload = json.dumps(result).encode('utf-8')
                        cf = APP_JSON
                    elif isinstance(result, str):
                        payload = result.encode('utf-8')
                        cf = TEXT_PLAIN
                    elif isinstance(result, (bytes, bytearray)):
                        payload = result
                        cf = resource.content_format
                    else:
                        payload = str(result).encode('utf-8')
                        cf = TEXT_PLAIN
                    return self._build_response(msg, CONTENT, payload, cf)
                except Exception as e:
                    print("[CoAP] GET handler error: {}".format(e))
                    return self._build_response(msg, INTERNAL_ERROR,
                                                b'Internal error')
            else:
                return self._build_response(msg, METHOD_NOT_ALLOWED,
                                            b'GET not supported')

        elif method_code == PUT:
            if resource.put_handler:
                try:
                    success = resource.put_handler(msg.payload)
                    if success:
                        return self._build_response(msg, CHANGED,
                                                    b'Changed')
                    else:
                        return self._build_response(msg, BAD_REQUEST,
                                                    b'Bad request')
                except Exception as e:
                    print("[CoAP] PUT handler error: {}".format(e))
                    return self._build_response(msg, INTERNAL_ERROR,
                                                b'Internal error')
            else:
                return self._build_response(msg, METHOD_NOT_ALLOWED,
                                            b'PUT not supported')

        else:
            return self._build_response(msg, METHOD_NOT_ALLOWED,
                                        b'Method not allowed')

    def _handle_discovery(self, request):
        """Handle /.well-known/core resource discovery."""
        links = []
        for path, res in self.resources.items():
            attrs = []
            if res.get_handler:
                attrs.append('GET')
            if res.put_handler:
                attrs.append('PUT')
            ct = res.content_format
            link = '<{}>;ct={};methods="{}"'.format(path, ct, ','.join(attrs))
            links.append(link)

        payload = ','.join(links).encode('utf-8')
        resp = self._build_response(request, CONTENT, payload)
        # Content-Format: application/link-format (40)
        resp.options.append(CoapOption(12, struct.pack('!B', 40)))
        return resp

    def start(self):
        """Start the CoAP server (blocking)."""
        self._sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self._sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self._sock.bind((self.host, self.port))
        self._sock.settimeout(1.0)  # 1 second timeout for graceful shutdown

        self._running = True
        print("[CoAP] Server listening on {}:{}".format(self.host, self.port))
        print("[CoAP] Registered resources: {}".format(
            list(self.resources.keys())))

        while self._running:
            try:
                data, addr = self._sock.recvfrom(1024)
                response = self._handle_request(data, addr)
                if response:
                    self._sock.sendto(response.encode(), addr)
            except OSError:
                # Timeout - allows checking self._running
                pass
            except Exception as e:
                print("[CoAP] Error: {}".format(e))

        self._sock.close()
        print("[CoAP] Server stopped")

    def stop(self):
        """Stop the CoAP server."""
        self._running = False


